public int[] countBits(int n) {
    int[] dp = new int[n+1];
    for (int i=1; i<=n; i++)
        dp[i] = dp[i>>1] + (i&1);
    return dp;
}

public int reverseBits(int n) {
    int res = 0;
    for (int i=0; i<32; i++) {
        res = (res << 1) | (n & 1);
        n >>>= 1;
    }
    return res;
}

public int[] dailyTemperatures(int[] temperatures) {
    int n=temperatures.length;
    int[] ans=new int[n];
    Deque<Integer> stack=new ArrayDeque<>();
    for (int i=0;i<n;i++) {
        while (!stack.isEmpty() && temperatures[i]>temperatures[stack.peek()]) {
            int idx=stack.pop();
            ans[idx]=i-idx;
        }
        stack.push(i);
    }
    return ans;
}

public int[] nextGreaterElement(int[] nums1, int[] nums2) {
    Map<Integer,Integer> nextGreater=new HashMap<>();
    Deque<Integer> stack=new ArrayDeque<>();
    for (int n:nums2) {
        while (!stack.isEmpty() && stack.peek()<n)
            nextGreater.put(stack.pop(), n);
        stack.push(n);
    }
    int[] res=new int[nums1.length];
    for (int i=0;i<nums1.length;i++)
        res[i]=nextGreater.getOrDefault(nums1[i],-1);
    return res;
}

public int largestRectangleArea(int[] heights) {
    Deque<Integer> stack=new ArrayDeque<>();
    int max=0;
    int[] h=Arrays.copyOf(heights, heights.length+1);
    for (int i=0;i<h.length;i++) {
        while (!stack.isEmpty() && h[i]<h[stack.peek()]) {
            int height=h[stack.pop()];
            int width=stack.isEmpty()?i:i-stack.peek()-1;
            max=Math.max(max, height*width);
        }
        stack.push(i);
    }
    return max;
}

public int trap(int[] height) {
    int left=0, right=height.length-1;
    int maxL=0, maxR=0, water=0;
    while (left < right) {
        if (height[left] < height[right]) {
            if (height[left] >= maxL) maxL=height[left];
            else water+=maxL-height[left];
            left++;
        } else {
            if (height[right] >= maxR) maxR=height[right];
            else water+=maxR-height[right];
            right--;
        }
    }
    return water;
}
